<!-- 修改要展示的markdown文件时，要修改两个路径以及一个正则表达式！！！ -->
<template>
  <div class="page-container">
    <el-container class="content-container">
      <el-header>
        <div class="header-content">Lysssyo's Personal Page</div>
      </el-header>

      <el-container>
        <el-aside style="width: 250px; border: 1px solid;">
          <el-col>
            <el-menu default-active="2" class="el-menu-vertical-demo">
              <el-submenu index="1">
                <template slot="title">
                  <i class="el-icon-reading"></i>
                  <span>Learning Notes</span>
                </template>
                <el-menu-item-group>
                  <el-menu-item index="1-1">Test</el-menu-item>
                  <el-menu-item index="1-2">选项2</el-menu-item>
                </el-menu-item-group>
              </el-submenu>
            </el-menu>
          </el-col>
        </el-aside>
        <el-main class="scrollable-content">
          <div class="inner-content" v-html="renderedMarkdown"></div>
        </el-main>
      </el-container>
    </el-container>
  </div>
</template>

<script>
import axios from 'axios';
import MarkdownIt from 'markdown-it';

export default {
  data() {
    return {
      decodedContentChunks: [],
      decodedContent: '',
      renderedMarkdown: '',
      searchKeyword: '',
      imagePositions: [] // 记录图片标签在原markdown中的位置
    };
  },
  mounted() {
    //!!!注意：修改要展示的markdown文件时，这里的路径要修改！
    axios.get('https://api.github.com/repos/Lysssyo/MyAlgorithm/contents/DataStructuresAlgorithm.md', {
      headers: {
        Authorization: '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'
      }
    })
      .then(response => {
        console.log(response.data.content); // 打印获取的数据

        this.decodedContent = decodeURIComponent(escape(atob(response.data.content)));

        this.decodeContent();
      })
      .catch(error => {
        console.error('Error fetching data:', error);
      });
  },
  methods: {
    decodeContent() {
      try {
        // 使用分块处理解码Base64编码的字符串
        const chunkSize = 8192; // 修改块大小为8192个字符
        for (let i = 0; i < this.decodedContent.length; i += chunkSize) {
          this.decodedContentChunks.push(this.decodedContent.slice(i, i + chunkSize));
        }
        // 将分块解码后的内容合并
        this.decodedContent = this.decodedContentChunks.join('');
        console.log(this.decodedContent); // 打印解码后的内容
        // 将解码后的 Markdown 转换为 HTML
        this.renderMarkdown();
      } catch (error) {
        console.error('Error decoding content:', error);
      }
    },
    renderMarkdown() {
      const md = new MarkdownIt();
      this.renderedMarkdown = md.render(this.decodedContent);

      const imageFileNames = this.extractImageFileNamesFromMarkdown(this.renderedMarkdown);

      // 替换图片标签
      imageFileNames.forEach(({ fileName, tag }) => {
        //注意！！！修改要展示的markdown文件时，这里的路径要修改！
        const imageUrl = `https://raw.githubusercontent.com/Lysssyo/MyAlgorithm/main/DataStructuresAlgorithm.assets/${fileName}`;
        console.log("图片的地址：：" + imageUrl);
        //如果没有找到正确的路径，不会显示错误的url也不会显示图像
        this.renderedMarkdown = this.renderedMarkdown.replace(tag, `<img src="${imageUrl}" alt="Image" />`);
      });
    },
    extractImageFileNamesFromMarkdown(markdown) {
      console.log(markdown);
      const imageFileNames = [];
      // 注意！！！修改要展示的 markdown 文件时，这里的正则表达式要修改！
      //const regex = /<p>&lt;img src=&quot;DataStructuresAlgorithm\.assets\\\\(.*?)\.png&quot; alt=&quot;(.*?)&quot; style=&quot;zoom:.*?;&quot; \/&gt; <\/p>/g;

      const regex = /<p>&lt;img src=&quot;DataStructuresAlgorithm\.assets\\(.*?)&quot; alt=&quot;.*?&quot; style=&quot;.*?&quot; \/&gt;<\/p>|<img\s+src="DataStructuresAlgorithm\.assets\/(.*?)"\s+alt=".*?"|<p>&lt;img src=&quot;DataStructuresAlgorithm\.assets\/(.*?)&quot; alt=&quot;.*?&quot; style=&quot;.*?&quot; \/&gt;<\/p>/g;


     
      let match;
      while ((match = regex.exec(markdown)) !== null) {
        //注意！！！如果缩放的图片后缀不为png，这里要修改!!!
        console.log("这是匹配结果！！！：：：：" + match);
        const fileName = match[1] || match[2] || match[3]; // 提取文件名
        const tag = match[0]; // 匹配的整个图片标签
        imageFileNames.push({ fileName, tag });
      }
      return imageFileNames;
    }
  }

};
</script>

<style>
.page-container {
  border: 1px solid gray;
  height: auto;
  border-radius: 15px;
  overflow: hidden;
}

.content-container {
  height: 100%;
