.el-header {
  background-color: darkgray;
}

.header-content {
  font-family: 'Microsoft YaHei', sans-serif;
  font-size: 35px;
  color: rgb(12, 13, 13);
}

.highlight {
  background-color: yellow;
  font-weight: bold;
}

.scrollable-content {
  overflow-y: auto;
  /* 垂直方向滚动条 */
  max-height: calc(100% - 50px);
  /* 减去页眉的高度 */
}

.inner-content {
  padding: 10px;
  /* 添加内边距 */
}

.fixed-menu {
  position: fixed;
  /* 固定菜单位置 */
  height: 100%;
}
</style>
